codeExamples.code:
console.log(a);  // undefined (var hoisted, not assigned yet)
var a = 10;

console.log(b);  // ReferenceError: Cannot access 'b' before initialization
let b = 20;

foo();  // 'foo called' (function declaration fully hoisted)
function foo() {
  console.log('foo called');
}

bar();  // TypeError: bar is not a function (var hoisted as undefined)
var bar = function() {
  console.log('bar called');
};

function first() {
  console.log('Inside first');
  second();
  console.log('Back in first');
}

function second() {
  console.log('Inside second');
  third();
  console.log('Back in second');
}

function third() {
  console.log('Inside third');
}

console.log('Global start');
first();
console.log('Global end');

// Output order:
// Global start
// Inside first
// Inside second
// Inside third
// Back in second
// Back in first
// Global end

console.log(this);  // window (global context)

function showThis() {
  console.log(this);  // window (non-strict) or undefined (strict)
}

const obj = {
  name: 'MyObj',
  showThis: function() {
    console.log(this);  // obj (method call)
  },
  arrowShow: () => {
    console.log(this);  // window (arrow inherits from global context)
  }
};

obj.showThis();    // obj
obj.arrowShow();   // window

const isolated = obj.showThis;
isolated();        // window (lost context, standalone call)

function Person(name) {
  this.name = name;  // new instance (constructor call)
}
const p = new Person('Alice');
console.log(p.name);  // 'Alice'

const globalVar = 'global';

function outer() {
  const outerVar = 'outer';

  function inner() {
    const innerVar = 'inner';
    console.log(innerVar);  // 'inner' (own scope)
    console.log(outerVar);  // 'outer' (one level up)
    console.log(globalVar); // 'global' (two levels up)
  }

  inner();
}

outer();

// Scope chain for inner():
// [inner's scope] -> [outer's scope] -> [global scope]

function sum(a, b) {
  console.log(arguments);
  // Arguments object: { 0: 10, 1: 20, length: 2, callee: sum }
  console.log(a, b);  // 10, 20
  return a + b;
}

sum(10, 20);

function dynamic() {
  console.log(arguments[0]);  // first argument
  console.log(arguments.length);  // number of arguments

  // Convert to array
  const args = Array.from(arguments);
  // or: const args = [...arguments];
  console.log(args);
}

dynamic(1, 2, 3, 4);  // arguments = { 0: 1, 1: 2, 2: 3, 3: 4 }
